wire           key_ready;

reg            enc_next;
wire [3 : 0]   enc_round_nr;
wire [127 : 0] enc_new_block;
wire           enc_ready;
wire [31 : 0]  enc_sboxw;

reg            dec_next;
wire [3 : 0]   dec_round_nr;
wire [127 : 0] dec_new_block;
wire           dec_ready;

reg [127 : 0]  muxed_new_block;
reg [3 : 0]    muxed_round_nr;
reg            muxed_ready;

wire [31 : 0]  keymem_sboxw;

reg [31 : 0]   muxed_sboxw;
wire [31 : 0]  new_sboxw;


//----------------------------------------------------------------
// Instantiations.
//----------------------------------------------------------------
aes_encipher_block enc_block(
                             .clk(clk),
                             .reset_n(reset_n),

                             .next(enc_next),

                             .keylen(keylen),
                             .round(enc_round_nr),
                             .round_key(round_key),

                             .sboxw(enc_sboxw),
                             .new_sboxw(new_sboxw),

                             .block(block),
                             .new_block(enc_new_block),
                             .ready(enc_ready)
                            );


aes_decipher_block dec_block(
                             .clk(clk),
                             .reset_n(reset_n),

                             .next(dec_next),

                             .keylen(keylen),
                             .round(dec_round_nr),
                             .round_key(round_key),

                             .block(block),
                             .new_block(dec_new_block),
                             .ready(dec_ready)
                            );


aes_key_mem keymem(
                   .clk(clk),
                   .reset_n(reset_n),

                   .key(key),
                   .keylen(keylen),
                   .init(init),

                   .round(muxed_round_nr),
                   .round_key(round_key),
                   .ready(key_ready),

                   .sboxw(keymem_sboxw),
                   .new_sboxw(new_sboxw)
                  );


aes_sbox sbox_inst(.sboxw(muxed_sboxw), .new_sboxw(new_sboxw));


//----------------------------------------------------------------
// Concurrent connectivity for ports etc.
//----------------------------------------------------------------
assign ready        = ready_reg;
